import { useSelector } from "react-redux";

function Home() {
  const user = useSelector((state) => state.auth.user);

  return (
    <div className="container mt-5">
      <div className="text-center">
        <h1 className="mb-4">Добро пожаловать в School App</h1>
        {user ? (
          <p className="lead">
            Здравствуйте, {user.name}! Вы вошли как {user.role}.
          </p>
        ) : (
          <p className="lead">
            Пожалуйста, <a href="/login" className="text-primary">войдите</a> или{" "}
            <a href="/register" className="text-primary">зарегистрируйтесь</a>.
          </p>
        )}
      </div>
    </div>
  );
}

export default Home;
